1	import { useEffect, useState } from "react";
2	import { useParams, useNavigate } from "react-router-dom";
3	import { supabase } from "@/integrations/supabase/client";
4	import { useAuth } from "@/contexts/AuthContext";
5	import { batchSignedUrls } from "@/lib/photo-utils";
6	import { ArrowLeft, Calendar, MapPin, Factory, Play, Video } from "lucide-react";
7	import { format } from "date-fns";
8	
9	interface PhotoItem {
10	  id: string;
11	  file_path: string;
12	  product_name: string | null;
13	  trip_id: string;
14	  thumbnail_path?: string | null;
15	  signed_url?: string;
16	  signed_thumbnail_url?: string;
17	  display_url?: string;
18	  media_type?: string | null;
19	}
20	
21	interface ChildTrip {
22	  id: string;
23	  supplier: string;
24	  date: string;
25	  venue_type: string;
26	}
27	
28	interface FairTrip {
29	  id: string;
30	  name: string;
31	  date: string;
32	  end_date: string | null;
33	  location: string | null;
34	}
35	
36	export default function FairTripStream() {
37	  const { id } = useParams<{ id: string }>();
38	  const navigate = useNavigate();
39	  const { user } = useAuth();
40	
41	  const [fairTrip, setFairTrip] = useState<FairTrip | null>(null);
42	  const [childTrips, setChildTrips] = useState<ChildTrip[]>([]);
43	  const [photosByTrip, setPhotosByTrip] = useState<Map<string, PhotoItem[]>>(new Map());
44	  const [loading, setLoading] = useState(true);
45	
46	  useEffect(() => {
47	    if (!user || !id) return;
48	    loadStream();
49	  }, [user, id]);
50	
51	  async function loadStream() {
52	    setLoading(true);
53	
54	    const { data: fairData } = await supabase
55	      .from("china_trips")
56	      .select("id, name, date, end_date, location")
57	      .eq("id", id!)
58	      .single();
59	    if (fairData) setFairTrip(fairData as FairTrip);
60	
61	    const { data: children } = await supabase
62	      .from("china_trips")
63	      .select("id, supplier, date, venue_type")
64	      .eq("parent_id", id!)
65	      .is("deleted_at", null)
66	      .order("date", { ascending: true });
67	
68	    if (!children || children.length === 0) {
69	      setLoading(false);
70	      return;
71	    }
72	    setChildTrips(children as ChildTrip[]);
73	
74	    const childIds = children.map((c) => c.id);
75	    const allPhotos: PhotoItem[] = [];
76	    for (let i = 0; i < childIds.length; i += 10) {
77	      const chunk = childIds.slice(i, i + 10);
78	      const { data } = await supabase
79	        .from("china_photos")
80	        .select("id, file_path, product_name, trip_id, thumbnail_path, media_type")
81	        .in("trip_id", chunk)
82	        .order("created_at", { ascending: true });
83	      if (data) allPhotos.push(...(data as PhotoItem[]));
84	    }
85	
86	    const urlMap = await batchSignedUrls(
87	      allPhotos.map((p) => ({ file_path: p.thumbnail_path || p.file_path }))
88	    );
89	    allPhotos.forEach((p) => {
90	      const displayPath = p.thumbnail_path || p.file_path;
91	      p.display_url = urlMap.get(displayPath);
92	      if (p.thumbnail_path) p.signed_thumbnail_url = p.display_url;
93	      else p.signed_url = p.display_url;
94	    });
95	
96	    const byTrip = new Map<string, PhotoItem[]>();
97	    for (const photo of allPhotos) {
98	      const list = byTrip.get(photo.trip_id) ?? [];
99	      list.push(photo);
100	      byTrip.set(photo.trip_id, list);
101	    }
102	    setPhotosByTrip(byTrip);
103	    setLoading(false);
104	  }
105	
106	  const totalPhotos = Array.from(photosByTrip.values()).reduce((sum, p) => sum + p.length, 0);
107	  const tripsWithPhotos = childTrips.filter((t) => (photosByTrip.get(t.id) ?? []).length > 0);
108	  const priorityPhotoIds = new Set(
109	    childTrips.flatMap((trip) => photosByTrip.get(trip.id) ?? []).slice(0, 36).map((photo) => photo.id)
110	  );
111	
112	  return (
113	    <div className="container py-6">
114	      <button
115	        onClick={() => navigate("/china")}
116	        className="mb-4 flex items-center gap-1 text-sm text-muted-foreground hover:text-foreground"
117	      >
118	        <ArrowLeft className="h-4 w-4" /> Back to Asia Trips
119	      </button>
120	
121	      <div className="mb-6">
122	        <div className="flex flex-wrap items-start justify-between gap-3">
123	          <h1 className="font-sans text-2xl md:text-3xl font-semibold">
124	            {fairTrip?.name ?? "Fair Trip"}
125	          </h1>
126	          <button
127	            onClick={() => navigate(`/china/${id}/stream-v2`)}
128	            className="text-sm font-medium text-primary hover:underline"
129	          >
130	            Try faster view
131	          </button>
132	        </div>
133	        {fairTrip && (
134	          <p className="mt-1 text-sm text-muted-foreground flex flex-wrap items-center gap-x-3 gap-y-1">
135	            <span className="flex items-center gap-1">
136	              <Calendar className="h-3.5 w-3.5" />
137	              {format(new Date(fairTrip.date), "MMM d")}
138	              {fairTrip.end_date && ` – ${format(new Date(fairTrip.end_date), "MMM d, yyyy")}`}
139	            </span>
140	            {fairTrip.location && (
141	              <span className="flex items-center gap-1">
142	                <MapPin className="h-3.5 w-3.5" /> {fairTrip.location}
143	              </span>
144	            )}
145	          </p>
146	        )}
147	        {!loading && (
148	          <p className="mt-0.5 text-sm text-muted-foreground">
149	            {tripsWithPhotos.length} booth{tripsWithPhotos.length !== 1 ? "s" : ""} · {totalPhotos} photo{totalPhotos !== 1 ? "s" : ""}
150	          </p>
151	        )}
152	      </div>
153	
154	      {loading ? (
155	        <div className="space-y-8">
156	          {[1, 2, 3].map((i) => (
157	            <div key={i}>
158	              <div className="mb-3 h-5 w-48 rounded bg-muted animate-pulse" />
159	              <div className="grid gap-1.5 grid-cols-3 sm:grid-cols-4 lg:grid-cols-6 xl:grid-cols-8">
160	                {Array.from({ length: 8 }).map((_, j) => (
161	                  <div key={j} className="aspect-square rounded-md bg-muted animate-pulse" />
162	                ))}
163	              </div>
164	            </div>
165	          ))}
166	        </div>
167	      ) : tripsWithPhotos.length === 0 ? (
168	        <div className="py-16 text-center text-muted-foreground text-sm">
169	          No photos found in this fair trip.
170	        </div>
171	      ) : (
172	        <div className="space-y-8">
173	          {childTrips.map((trip, idx) => {
174	            const photos = photosByTrip.get(trip.id) ?? [];
175	            if (photos.length === 0) return null;
176	            return (
177	              <div key={trip.id}>
178	                {idx > 0 && tripsWithPhotos.indexOf(trip) > 0 && <div className="border-t mb-6" />}
179	                <button
180	                  onClick={() => navigate(`/china/${trip.id}`)}
181	                  className="mb-3 flex flex-wrap items-center gap-x-2 gap-y-0.5 group text-left"
182	                >
183	                  <h2 className="font-sans text-base font-semibold group-hover:text-primary transition-colors">
184	                    {trip.supplier}
185	                  </h2>
186	                  <span className="text-xs text-muted-foreground">
187	                    {format(new Date(trip.date), "MMM d")} · {photos.length} photo{photos.length !== 1 ? "s" : ""}
188	                  </span>
189	                </button>
190	                <div className="grid gap-1.5 grid-cols-3 sm:grid-cols-4 lg:grid-cols-6 xl:grid-cols-8">
191	                  {photos.map((photo) => {
192	                    const isVideo = photo.media_type === "video";
193	                    const thumb = photo.display_url;
194	                    const isPriority = priorityPhotoIds.has(photo.id);
195	                    return (
196	                      <div
197	                        key={photo.id}
198	                        className="group relative aspect-square cursor-pointer overflow-hidden rounded-md bg-muted"
199	                        onClick={() => navigate(`/china/${trip.id}`)}
200	                      >
201	                        {isVideo ? (
202	                          <>
203	                            {thumb ? (
204	                              <img
205	                                src={thumb}
206	                                alt={photo.product_name ?? "Video"}
207	                                className="h-full w-full object-cover"
208	                                loading={isPriority ? "eager" : "lazy"}
209	                                decoding="auto"
210	                                draggable={false}
211	                              />
212	                            ) : (
213	                              <div className="flex h-full w-full items-center justify-center bg-black/80">
214	                                <Video className="h-6 w-6 text-white/70" />
215	                              </div>
216	                            )}
217	                            <div className="absolute inset-0 flex items-center justify-center">
218	                              <div className="rounded-full bg-black/60 p-2 backdrop-blur-sm">
219	                                <Play className="h-4 w-4 fill-white text-white" />
220	                              </div>
221	                            </div>
222	                          </>
223	                        ) : (
224	                          thumb ? (
225	                            <img
226	                              src={thumb}
227	                              alt={photo.product_name ?? "Photo"}
228	                              className="h-full w-full object-cover"
229	                              loading={isPriority ? "eager" : "lazy"}
230	                              decoding="auto"
231	                              draggable={false}
232	                            />
233	                          ) : (
234	                            <div className="flex h-full w-full items-center justify-center">
235	                              <Factory className="h-6 w-6 text-muted-foreground/30" />
236	                            </div>
237	                          )
238	                        )}
239	                        {photo.product_name && (
240	                          <div className="absolute bottom-0 left-0 right-0 bg-gradient-to-t from-black/60 to-transparent p-1.5">
241	                            <p className="text-[10px] text-white truncate">{photo.product_name}</p>
242	                          </div>
243	                        )}
244	                      </div>
245	                    );
246	                  })}
247	                </div>
248	              </div>
249	            );
250	          })}
251	        </div>
252	      )}
253	    </div>
254	  );
255	}
