1	import { useEffect, useState, useRef } from "react";
2	import CachedImage from "@/components/CachedImage";
3	import { useParams, useNavigate } from "react-router-dom";
4	import { supabase } from "@/integrations/supabase/client";
5	import { useAuth } from "@/contexts/AuthContext";
6	import { resizeToBase64 } from "@/lib/image-utils";
