154	  function buildFileName(photo: Photo, indexInGroup?: number): string {
155	    const ext = photo.file_path.split(".").pop() || "jpg";
156	    const dateStr = trip?.date || photo.created_at;
157	    const d = new Date(dateStr);
158	    const yyyymmdd = `${d.getFullYear()}${String(d.getMonth() + 1).padStart(2, "0")}${String(d.getDate()).padStart(2, "0")}`;
159	    const supplierName = (trip?.supplier || "Supplier").replace(/[^a-zA-Z0-9]/g, "");
