165	  async function handleDownloadAll() {
166	    if (photos.length === 0) return;
167	    setDownloading(true);
168	    let count = 0;
169	    const groups = groupPhotos(photos);
170	    const downloadList: { photo: Photo; fileName: string }[] = [];
171	    for (const { primary, extras } of groups) {
172	      downloadList.push({ photo: primary, fileName: buildFileName(primary, 1) });
173	      extras.forEach((ex, i) => {
174	        downloadList.push({ photo: ex, fileName: buildFileName(primary, i + 2) });
175	      });
176	    }
177	    for (const { photo, fileName } of downloadList) {
178	      try {
179	        const url = photo.signed_url;
180	        if (!url) continue;
181	        const res = await fetch(url);
182	        const blob = await res.blob();
183	        const a = document.createElement("a");
184	        a.href = URL.createObjectURL(blob);
185	        a.download = fileName;
186	        document.body.appendChild(a);
187	        a.click();
188	        document.body.removeChild(a);
189	        URL.revokeObjectURL(a.href);
190	        count++;
191	        await new Promise((r) => setTimeout(r, 300));
192	      } catch (err) {
193	        console.error("Download failed for:", photo.id, err);
194	      }
195	    }
196	    setDownloading(false);
