212	    let businessCardsFound = 0;
213	
214	    for (let i = 0; i < photosWithoutMeta.length; i++) {
215	      const photo = photosWithoutMeta[i];
216	      setBulkAnalyzeProgress(Math.round((i / photosWithoutMeta.length) * 100));
217	      try {
218	        const res = await fetch(photo.signed_url!);
219	        const blob = await res.blob();
220	        const { base64, mimeType } = await resizeToBase64(blob);
221	        const { data, error } = await supabase.functions.invoke("analyze-photo", {
222	          body: { imageBase64: base64, mimeType, categories },
223	        });
224	        if (error) continue;
225	
226	        // Handle business card detection
227	        if (data.is_business_card && data.company_name && user && id) {
228	          businessCardsFound++;
229	          const { data: newFactory, error: factoryError } = await supabase
230	            .from("factories")
