273	      ? `${success} photos updated. ${businessCardsFound} business card(s) detected and saved.`
274	      : `${success} of ${photosWithoutMeta.length} photos updated.`;
275	    toast({ title: "Bulk AI detection complete", description });
276	    loadPhotos();
277	  }
