447	  async function checkGeoFence(files: File[]): Promise<{ ok: File[]; warned: File[] }> {
448	    const ok: File[] = [];
449	    const warned: File[] = [];
450	    for (const file of files) {
451	      const exif = await extractExif(file);
452	      if (exif.latitude != null && exif.longitude != null && isInAmericas(exif.latitude, exif.longitude)) {
453	        warned.push(file);
454	      } else {
455	        ok.push(file);
456	      }
457	    }
458	    return { ok, warned };
459	  }
