469	          setGeoWarningType("single");
470	          setShowGeoWarning(true);
471	        } else {
472	          openSingleUpload(file);
473	        }
474	      });
475	    } else {
476	      const fileArray = Array.from(files);
477	      checkGeoFence(fileArray).then(({ ok, warned }) => {
478	        if (warned.length > 0 && ok.length === 0) {
479	          setGeoWarningFiles(warned);
480	          setGeoWarningType("bulk");
481	          setShowGeoWarning(true);
482	        } else if (warned.length > 0) {
483	          handleBulkUpload(ok);
484	          setGeoWarningFiles(warned);
485	          setGeoWarningType("bulk");
486	          setShowGeoWarning(true);
487	        } else {
488	          handleBulkUpload(ok);
489	        }
