520	  async function handleBulkUpload(files: File[]) {
521	    if (!user || !id) return;
522	    setUploading(true);
523	    let queuedCount = 0;
524	    let dupCount = 0;
525	    for (const file of files) {
526	      const fileHash = await hashFile(file);
527	      if (await checkDuplicatePhoto(fileHash)) { dupCount++; continue; }
528	      await addPendingUpload({
529	        id: crypto.randomUUID(), trip_id: id, file_blob: file, file_name: file.name,
530	        metadata: { product_name: null, category: null, price: null, dimensions: null, country_of_origin: null, material: null, brand: null, notes: null },
531	        table: "china_photos",
532	        user_id: user.id, created_at: new Date().toISOString(), status: "pending", retry_count: 0,
533	      });
