9	interface PhotoItem {
10	  id: string;
11	  file_path: string;
12	  product_name: string | null;
13	  trip_id: string;
14	  thumbnail_path?: string | null;
15	  signed_url?: string;
16	  signed_thumbnail_url?: string;
17	  media_type?: string | null;
18	}
19	
20	interface VisitInfo {
21	  supplier: string;
22	  tripIds: string[];
23	  factory: {
24	    contact_person: string | null;
25	    phone: string | null;
26	  } | null;
27	}
28	
29	interface StreamState {
30	  label: string;
31	  visits: VisitInfo[];
32	}
33	
34	export default function FactoryWeekStream() {
35	  const navigate = useNavigate();
36	  const location = useLocation();
37	  const { user } = useAuth();
38	
39	  const state = (location.state as StreamState | null);
40	  const label = state?.label ?? "";
41	  const visits = state?.visits ?? [];
42	
43	  const [photosBySupplier, setPhotosBySupplier] = useState<Map<string, PhotoItem[]>>(new Map());
44	  const [loading, setLoading] = useState(true);
45	
46	  useEffect(() => {
47	    if (!user || visits.length === 0) {
48	      setLoading(false);
49	      return;
50	    }
51	    loadStream();
52	  }, [user]);
53	
54	  async function loadStream() {
55	    setLoading(true);
56	
57	    const allTripIds = visits.flatMap((v) => v.tripIds);
58	    // Build a map from tripId → supplier for grouping
59	    const tripToSupplier = new Map<string, string>();
60	    for (const visit of visits) {
61	      for (const tid of visit.tripIds) {
62	        tripToSupplier.set(tid, visit.supplier);
63	      }
64	    }
65	
66	    const allPhotos: PhotoItem[] = [];
67	    for (let i = 0; i < allTripIds.length; i += 10) {
68	      const chunk = allTripIds.slice(i, i + 10);
69	      const { data } = await supabase
70	        .from("china_photos")
71	        .select("id, file_path, product_name, trip_id, thumbnail_path, media_type")
72	        .in("trip_id", chunk)
73	        .order("created_at", { ascending: true });
74	      if (data) allPhotos.push(...(data as PhotoItem[]));
75	    }
76	
77	    const urlMap = await batchSignedUrls(
78	      allPhotos.map((p) => ({ file_path: p.file_path, thumbnail_path: p.thumbnail_path ?? null }))
79	    );
80	    allPhotos.forEach((p) => {
81	      p.signed_url = urlMap.get(p.file_path);
82	      if (p.thumbnail_path) p.signed_thumbnail_url = urlMap.get(p.thumbnail_path);
83	    });
84	
85	    // Group by supplier (normalized)
86	    const bySupplier = new Map<string, PhotoItem[]>();
87	    for (const photo of allPhotos) {
88	      const supplierKey = (tripToSupplier.get(photo.trip_id) ?? "").trim().toLowerCase();
89	      const list = bySupplier.get(supplierKey) ?? [];
90	      list.push(photo);
91	      bySupplier.set(supplierKey, list);
92	    }
93	    setPhotosBySupplier(bySupplier);
94	    setLoading(false);
95	  }
