97	  const totalPhotos = Array.from(photosBySupplier.values()).reduce((sum, p) => sum + p.length, 0);
98	  const suppliersWithPhotos = visits.filter(
99	    (v) => (photosBySupplier.get(v.supplier.trim().toLowerCase()) ?? []).length > 0
100	  );
101	
102	  if (!state) {
103	    return (
