129	            {suppliersWithPhotos.length} factor{suppliersWithPhotos.length !== 1 ? "ies" : "y"} · {totalPhotos} photo{totalPhotos !== 1 ? "s" : ""}
130	          </p>
131	        )}
132	      </div>
133	
134	      {loading ? (
135	        <div className="space-y-8">
136	          {[1, 2, 3].map((i) => (
