139	              <div className="grid gap-1.5 grid-cols-3 sm:grid-cols-4 lg:grid-cols-6 xl:grid-cols-8">
140	                {Array.from({ length: 8 }).map((_, j) => (
141	                  <div key={j} className="aspect-square rounded-md bg-muted animate-pulse" />
142	                ))}
143	              </div>
144	            </div>
145	          ))}
146	        </div>
