5	/** Group photos: primary photos (no group_id) with their children */
6	export function groupPhotos(photos: Photo[]): { primary: Photo; extras: Photo[] }[] {
7	  const grouped = new Map<string, Photo[]>();
8	  const primaries: Photo[] = [];
9	
10	  for (const p of photos) {
11	    if (p.group_id) {
12	      const list = grouped.get(p.group_id) || [];
13	      list.push(p);
14	      grouped.set(p.group_id, list);
15	    } else {
16	      primaries.push(p);
17	    }
18	  }
19	
20	  return primaries.map((p) => ({
21	    primary: p,
22	    extras: grouped.get(p.id) || [],
23	  }));
24	}
