26	/** Group photo cards by section, preserving order (null/unsectioned first) */
27	export function groupBySection(groups: { primary: Photo; extras: Photo[] }[]): { section: string | null; items: { primary: Photo; extras: Photo[] }[] }[] {
28	  const sectionOrder: (string | null)[] = [];
29	  const map = new Map<string | null, { primary: Photo; extras: Photo[] }[]>();
30	  for (const g of groups) {
31	    const sec = g.primary.section ?? null;
32	    if (!map.has(sec)) {
33	      sectionOrder.push(sec);
34	      map.set(sec, []);
35	    }
36	    map.get(sec)!.push(g);
37	  }
38	  const nullIdx = sectionOrder.indexOf(null);
39	  if (nullIdx > 0) {
40	    sectionOrder.splice(nullIdx, 1);
41	    sectionOrder.unshift(null);
42	  }
43	  return sectionOrder.map((sec) => ({ section: sec, items: map.get(sec)! }));
44	}
