46	const SIGNED_URL_TTL = 86400; // 24 hours
47	const SIGNED_URL_TTL_MS = SIGNED_URL_TTL * 1000;
48	
49	/**
50	 * Batch-generate signed URLs for an array of photos.
51	 * Also signs thumbnail_path when available.
52	 * Checks IndexedDB cache first — only requests URLs for uncached/expired paths.
53	 * Falls back to individual requests if the batch API fails.
54	 */
55	export async function batchSignedUrls(photos: { file_path: string; thumbnail_path?: string | null }[]): Promise<Map<string, string>> {
56	  const urlMap = new Map<string, string>();
57	  if (photos.length === 0) return urlMap;
58	
59	  // Collect all paths (originals + thumbnails)
60	  const allPaths: string[] = [];
61	  for (const p of photos) {
62	    allPaths.push(p.file_path);
63	    if (p.thumbnail_path) allPaths.push(p.thumbnail_path);
64	  }
65	
66	  // Check cache first
67	  const cached = await getCachedSignedUrls(allPaths);
68	  cached.forEach((url, path) => urlMap.set(path, url));
69	
70	  // Determine which paths still need fetching
71	  const uncachedPaths = allPaths.filter((p) => !urlMap.has(p));
72	  if (uncachedPaths.length === 0) return urlMap;
73	
74	  try {
75	    const { data, error } = await supabase.storage
76	      .from("photos")
77	      .createSignedUrls(uncachedPaths, SIGNED_URL_TTL);
78	
79	    if (!error && data) {
80	      const toCache: CachedSignedUrl[] = [];
81	      for (const item of data) {
82	        if (item.signedUrl && item.path) {
83	          urlMap.set(item.path, item.signedUrl);
84	          toCache.push({
85	            file_path: item.path,
86	            url: item.signedUrl,
87	            expires_at: Date.now() + SIGNED_URL_TTL_MS,
88	          });
89	        }
90	      }
91	      // Cache in background — don't block
92	      cacheSignedUrls(toCache).catch(() => {});
93	    }
94	  } catch {
95	    // Fallback: individual requests
96	    for (const path of uncachedPaths) {
97	      try {
98	        const { data } = await supabase.storage
99	          .from("photos")
100	          .createSignedUrl(path, SIGNED_URL_TTL);
101	        if (data?.signedUrl) {
102	          urlMap.set(path, data.signedUrl);
103	          cacheSignedUrls([{ file_path: path, url: data.signedUrl, expires_at: Date.now() + SIGNED_URL_TTL_MS }]).catch(() => {});
104	        }
105	      } catch {}
106	    }
107	  }
108	
109	  return urlMap;
110	}
